async function sGet(k,fb){try{if(window.storage){const r=await window.storage.get(k);return r?JSON.parse(r.value):fb;}const v=localStorage.getItem(k);return v?JSON.parse(v):fb;}catch{return fb;}}
async function sSet(k,v){try{if(window.storage){await window.storage.set(k,JSON.stringify(v));return;}localStorage.setItem(k,JSON.stringify(v));}catch(e){console.error("storage:",e);}}

const CSS=`@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&family=Figtree:wght@300;400;500;600;700&display=swap');
:root{--bg0:#07070e;--bg1:#0e0e1a;--bg2:#141422;--bg3:#1a1a2e;--b1:#1c1c30;--b2:#252540;--b3:#35355a;--t1:#eef0f6;--t2:#8b8fad;--t3:#4e5175;--ac:#f59e0b;--acs:rgba(245,158,11,.08);--acb:rgba(245,158,11,.25);--dg:#ef4444;--ok:#22c55e;--oks:rgba(34,197,94,.1);--fd:'Outfit',sans-serif;--fb:'Figtree',sans-serif;--r1:6px;--r2:10px;--r3:14px;--tr:.2s cubic-bezier(.4,0,.2,1)}
*{box-sizing:border-box;margin:0;padding:0}body{background:var(--bg0);font-family:var(--fb);color:var(--t1)}
@keyframes fi{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}@keyframes sp{to{transform:rotate(360deg)}}@keyframes si2{from{opacity:0;transform:translateX(-12px)}to{opacity:1;transform:translateX(0)}}@keyframes ti{from{opacity:0;transform:translateY(20px) scale(.95)}to{opacity:1;transform:translateY(0) scale(1)}}@keyframes to2{from{opacity:1}to{opacity:0;transform:translateY(20px) scale(.9)}}@keyframes stepPop{0%{transform:scale(.8);opacity:0}100%{transform:scale(1);opacity:1}}
.fi{animation:fi .35s ease-out forwards}.si{animation:si2 .3s ease-out forwards}
::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:var(--bg0)}::-webkit-scrollbar-thumb{background:var(--b2);border-radius:3px}
input:focus,textarea:focus,select:focus{border-color:var(--ac)!important;box-shadow:0 0 0 3px var(--acs)!important;outline:none}
.card{background:var(--bg2);border:1px solid var(--b1);border-radius:var(--r3)}
.ba{background:linear-gradient(135deg,#d97706,#f59e0b);color:#000;border:none;border-radius:var(--r2);padding:11px 24px;font-size:13.5px;font-weight:600;cursor:pointer;font-family:var(--fb);transition:all var(--tr)}.ba:hover{transform:translateY(-1px)}.ba:disabled{opacity:.4;cursor:not-allowed;transform:none}
.bg2{background:var(--bg2);border:1px solid var(--b2);color:var(--t2);border-radius:var(--r2);padding:11px 18px;font-size:13.5px;font-weight:500;cursor:pointer;font-family:var(--fb);transition:all var(--tr)}.bg2:hover{border-color:var(--b3);color:var(--t1)}
.fl label{display:block;font-size:11px;font-weight:600;color:var(--t3);margin-bottom:6px;text-transform:uppercase;letter-spacing:.8px}
.fl input,.fl textarea,.fl select{width:100%;padding:10px 13px;border:1px solid var(--b2);border-radius:var(--r1);font-size:13.5px;color:var(--t1);font-family:var(--fb);background:var(--bg1)}.fl select option{background:var(--bg3)}
.tb{padding:11px 18px;background:transparent;border:none;border-bottom:2px solid transparent;color:var(--t3);font-size:13px;font-weight:600;cursor:pointer;font-family:var(--fb);white-space:nowrap}.tb.ac{border-bottom-color:var(--ac);color:var(--ac)}
.nr{background:var(--bg2);border:1px solid var(--b1);border-radius:var(--r2);padding:16px 20px;display:flex;align-items:center;gap:16px;transition:all var(--tr);cursor:pointer}.nr:hover{border-color:var(--acb);transform:translateY(-1px)}
.sd{width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;flex-shrink:0;font-family:var(--fd)}.sd-a{background:var(--ac);color:#000}.sd-d{background:var(--ok);color:#fff}.sd-i{background:var(--bg3);color:var(--t3);border:1px solid var(--b2)}
.tc{position:fixed;bottom:24px;right:24px;z-index:9999;display:flex;flex-direction:column;gap:8px;align-items:flex-end}.tt{padding:14px 20px;border-radius:var(--r2);font-size:13.5px;font-weight:500;font-family:var(--fb);box-shadow:0 8px 32px rgba(0,0,0,.5);animation:ti .3s ease-out forwards;display:flex;align-items:center;gap:10px;max-width:380px}.tt-x{animation:to2 .25s ease-in forwards}.tt-s{background:rgba(34,197,94,.15);border:1px solid rgba(34,197,94,.3);color:var(--ok)}.tt-e{background:rgba(239,68,68,.15);border:1px solid rgba(239,68,68,.3);color:#fca5a5}.tt-i{background:rgba(245,158,11,.12);border:1px solid rgba(245,158,11,.3);color:var(--ac)}
.db{display:inline-flex;align-items:center;gap:6px;background:rgba(245,158,11,.1);border:1px solid rgba(245,158,11,.2);color:var(--ac);font-size:11px;font-weight:600;padding:4px 10px;border-radius:99px}
.tip{position:relative;display:inline-flex;align-items:center;gap:4px}.tip .ti2{width:15px;height:15px;border-radius:50%;background:var(--b2);color:var(--t3);font-size:9px;display:inline-flex;align-items:center;justify-content:center;cursor:help;font-weight:700}.tip .tb2{display:none;position:absolute;left:calc(100% + 8px);top:50%;transform:translateY(-50%);background:var(--bg3);border:1px solid var(--b2);border-radius:var(--r1);padding:8px 12px;font-size:11px;color:var(--t2);width:220px;z-index:50;line-height:1.5}.tip:hover .tb2{display:block}
.gs{display:flex;align-items:center;gap:12px;font-size:13px;animation:stepPop .3s ease-out forwards}.gs-d{width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;flex-shrink:0}.gs-ok{background:var(--ok);color:#fff}.gs-w{background:var(--bg3);color:var(--t3)}.gs-sp{width:24px;height:24px;border:2.5px solid var(--b2);border-top:2.5px solid var(--ac);border-radius:50%;animation:sp .8s linear infinite}
.sl{font-size:11px;font-weight:600;color:var(--ac);text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;font-family:var(--fd);display:flex;align-items:center;gap:8px}.sl::before{content:'';width:16px;height:2px;background:var(--ac)}
.dt{width:100%;border-collapse:collapse;margin:10px 0 16px;font-size:12.5px}.dt th{background:var(--bg3);color:var(--t2);padding:8px 10px;text-align:left;font-size:10px;text-transform:uppercase;border:1px solid var(--b2);font-weight:600}.dt td{padding:2px;border:1px solid var(--b2)}.dt input{width:100%;padding:7px 8px;border:none;background:transparent;color:var(--t1);font-size:12px;font-family:var(--fb);outline:none}.dt input:focus{background:var(--bg3)}
.ro{display:inline-flex;align-items:center;gap:6px;cursor:pointer;font-size:13px;color:var(--t2);margin-right:16px}.ro input[type=radio]{accent-color:var(--ac)}
.of textarea{width:100%;padding:10px 13px;border:1px solid var(--b2);border-radius:var(--r1);font-size:13px;color:var(--t1);font-family:var(--fb);background:var(--bg1);resize:vertical;min-height:60px}
.ob-steps{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;margin-top:32px}.ob-s{padding:24px 16px;border-radius:var(--r3);border:1px solid var(--b1);background:var(--bg2);text-align:center}.ob-n{width:32px;height:32px;border-radius:50%;background:var(--acs);color:var(--ac);font-weight:700;font-size:13px;display:flex;align-items:center;justify-content:center;margin:0 auto 12px;font-family:var(--fd)}
@media(max-width:768px){.do{display:none!important}.ms{flex-direction:column!important;gap:12px!important}.mp{padding:14px!important}.gr{grid-template-columns:1fr!important}.g3{grid-template-columns:1fr!important}.ob-steps{grid-template-columns:1fr!important}}`;

let _tid=0;
function Toasts({ts,rm}){return<div className="tc">{ts.map(t=><div key={t.id} className={`tt tt-${t.type} ${t.ex?"tt-x":""}`} onClick={()=>rm(t.id)}><span>{t.type==="s"?"✓":t.type==="e"?"✕":"ℹ"}</span><span>{t.msg}</span></div>)}</div>}
function useToast(){const[ts,setTs]=useState([]);const add=useCallback((msg,type="i",dur=3500)=>{const id=++_tid;setTs(p=>[...p,{id,msg,type,ex:false}]);setTimeout(()=>{setTs(p=>p.map(t=>t.id===id?{...t,ex:true}:t));setTimeout(()=>setTs(p=>p.filter(t=>t.id!==id)),300);},dur);},[]);const rm=useCallback(id=>{setTs(p=>p.map(t=>t.id===id?{...t,ex:true}:t));setTimeout(()=>setTs(p=>p.filter(t=>t.id!==id)),300);},[]);return{ts,add,rm};}

function SI({label,field,placeholder,type="text",form,upd,req,tip,span}){return<div className="fl" style={span?{gridColumn:`span ${span}`}:{}}><label>{label}{req&&<span style={{color:"var(--dg)",marginLeft:2}}>*</span>}{tip&&<span className="tip" style={{marginLeft:4}}><span className="ti2">?</span><span className="tb2">{tip}</span></span>}</label><input type={type} value={form[field]||""} onChange={e=>upd(field,e.target.value)} placeholder={placeholder}/></div>}
function OBS({label,field,form,upd,placeholder}){return<div className="of" style={{marginBottom:14}}><label style={{display:"block",fontSize:11,fontWeight:600,color:"var(--t3)",marginBottom:6,textTransform:"uppercase",letterSpacing:.8}}>{label}</label><textarea value={form[field]||""} onChange={e=>upd(field,e.target.value)} placeholder={placeholder||"Observations…"} rows={2}/></div>}
function Rad({label,field,form,upd}){return<div style={{display:"flex",alignItems:"center",gap:16,marginBottom:10}}><span style={{fontSize:13,color:"var(--t2)",minWidth:200}}>{label}</span><label className="ro"><input type="radio" name={field} checked={form[field]==="oui"} onChange={()=>upd(field,"oui")}/>Oui</label><label className="ro"><input type="radio" name={field} checked={form[field]==="non"} onChange={()=>upd(field,"non")}/>Non</label></div>}
function CI(){return<svg width="10" height="10" viewBox="0 0 12 12" fill="none"><path d="M2 6l3 3 5-5" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
function Empty({icon,title,sub,action,al}){return<div style={{padding:"48px 24px",textAlign:"center",border:"1px dashed var(--b2)",borderRadius:"var(--r3)"}}><div style={{fontSize:40,marginBottom:14}}>{icon}</div><h3 style={{color:"var(--t1)",fontFamily:"var(--fd)",fontWeight:700,fontSize:17,marginBottom:6}}>{title}</h3>{sub&&<p style={{color:"var(--t3)",fontSize:13.5,marginBottom:22,maxWidth:340,margin:"0 auto 22px"}}>{sub}</p>}{action&&<button className="ba" onClick={action}>{al}</button>}</div>}
function SB({v,onChange,ph}){return<div style={{position:"relative",display:"inline-block"}}><span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",fontSize:14,color:"var(--t3)",pointerEvents:"none"}}>🔍</span><input className="si2" style={{background:"var(--bg1)",border:"1px solid var(--b2)",borderRadius:"var(--r2)",padding:"9px 14px 9px 36px",fontSize:13,color:"var(--t1)",fontFamily:"var(--fb)",width:260,outline:"none"}} type="text" value={v} onChange={e=>onChange(e.target.value)} placeholder={ph}/>{v&&<button onClick={()=>onChange("")} style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:"var(--t3)",cursor:"pointer",fontSize:12}}>✕</button>}</div>}

function NivT({rows,upd}){const u=(i,k,v)=>{const n=[...rows];n[i]={...n[i],[k]:v};upd("niveauxRows",n);};return<div><table className="dt"><thead><tr><th>Niveau</th><th>Activités</th><th>Locaux</th><th>Surface m²</th><th>Mode calcul</th><th>Eff. public</th><th>Eff. pers.</th><th style={{width:30}}></th></tr></thead><tbody>{rows.map((r,i)=><tr key={i}>{["niveau","activites","locaux","surface","modeCalcul","effectifPublic","effectifPersonnel"].map(k=><td key={k}><input value={r[k]||""} onChange={e=>u(i,k,e.target.value)}/></td>)}<td><button onClick={()=>{if(rows.length>1)upd("niveauxRows",rows.filter((_,j)=>j!==i));}} style={{background:"none",border:"none",color:"var(--dg)",cursor:"pointer",fontSize:14}}>✕</button></td></tr>)}</tbody></table><button onClick={()=>upd("niveauxRows",[...rows,{...ER}])} style={{fontSize:12,color:"var(--ac)",background:"none",border:"1px dashed var(--acb)",borderRadius:"var(--r1)",padding:"6px 14px",cursor:"pointer"}}>+ Ajouter</button></div>}
function DegT({rows,upd}){const u=(i,k,v)=>{const n=[...rows];n[i]={...n[i],[k]:v};upd("degagementsRows",n);};return<div><table className="dt"><thead><tr><th>Niveau</th><th>Effectif</th><th>Eff. cumulé</th><th>Sorties régl.</th><th>UP régl.</th><th>Sorties prév.</th><th>UP prév.</th><th style={{width:30}}></th></tr></thead><tbody>{rows.map((r,i)=><tr key={i}>{["niveau","effectif","effectifCumule","sortiesRegl","upRegl","sortiesPrevues","upPrevues"].map(k=><td key={k}><input value={r[k]||""} onChange={e=>u(i,k,e.target.value)}/></td>)}<td><button onClick={()=>{if(rows.length>1)upd("degagementsRows",rows.filter((_,j)=>j!==i));}} style={{background:"none",border:"none",color:"var(--dg)",cursor:"pointer",fontSize:14}}>✕</button></td></tr>)}</tbody></table><button onClick={()=>upd("degagementsRows",[...rows,{...ED}])} style={{fontSize:12,color:"var(--ac)",background:"none",border:"1px dashed var(--acb)",borderRadius:"var(--r1)",padding:"6px 14px",cursor:"pointer"}}>+ Ajouter</button></div>}
function DesT({rows,upd}){const u=(i,k,v)=>{const n=[...rows];n[i]={...n[i],[k]:v};upd("desenfumageRows",n);};return<div><table className="dt"><thead><tr><th>Local</th><th>Superficie</th><th>Type désenfumage</th><th>Observations</th><th style={{width:30}}></th></tr></thead><tbody>{rows.map((r,i)=><tr key={i}>{["local","superficie","typeDesenfumage","observations"].map(k=><td key={k}><input value={r[k]||""} onChange={e=>u(i,k,e.target.value)}/></td>)}<td><button onClick={()=>{if(rows.length>1)upd("desenfumageRows",rows.filter((_,j)=>j!==i));}} style={{background:"none",border:"none",color:"var(--dg)",cursor:"pointer",fontSize:14}}>✕</button></td></tr>)}</tbody></table><button onClick={()=>upd("desenfumageRows",[...rows,{...EDF}])} style={{fontSize:12,color:"var(--ac)",background:"none",border:"1px dashed var(--acb)",borderRadius:"var(--r1)",padding:"6px 14px",cursor:"pointer"}}>+ Ajouter</button></div>}

function Plan({plan,setPlan}){const[tool,setTool]=useState("wall");const[dr,setDr]=useState(false);const[st,setSt]=useState(null);const[sl,setSl]=useState(false);const[pd,setPd]=useState(null);const[rn,setRn]=useState("");const paint=useCallback((r,c)=>{if(r<0||r>=RO2||c<0||c>=CO2)return;if(tool==="room"){setPd({r,c});setSl(true);return;}setPlan(p=>{const k=ck2(r,c);if(p[k]?.type===tool){const{[k]:_,...rest}=p;return rest;}return{...p,[k]:{type:tool}};});},[tool,setPlan]);const fill=useCallback((r1,c1,r2,c2)=>{const[a,b]=[Math.min(r1,r2),Math.max(r1,r2)];const[c,d]=[Math.min(c1,c2),Math.max(c1,c2)];setPlan(p=>{const n={...p};for(let r=a;r<=b;r++)for(let cc=c;cc<=d;cc++)n[ck2(r,cc)]={type:"wall"};return n;});},[setPlan]);const conf=()=>{if(!pd)return;setPlan(p=>({...p,[ck2(pd.r,pd.c)]:{type:"room",label:rn||"Local"}}));setRn("");setSl(false);setPd(null);};return<div><div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>{PT.map(t=><button key={t.id} onClick={()=>setTool(t.id)} style={{padding:"6px 13px",borderRadius:"var(--r1)",fontSize:12,fontWeight:600,cursor:"pointer",border:`1.5px solid ${tool===t.id?t.color:"var(--b2)"}`,background:tool===t.id?`${t.color}18`:"var(--bg1)",color:tool===t.id?t.color:"var(--t3)"}}>{t.label}</button>)}<button onClick={()=>setPlan({})} style={{marginLeft:"auto",padding:"6px 13px",borderRadius:"var(--r1)",fontSize:12,background:"var(--bg1)",border:"1px solid var(--b2)",color:"var(--t3)",cursor:"pointer"}}>Effacer</button></div>{sl&&<div style={{display:"flex",gap:8,marginBottom:14,alignItems:"center"}}><input autoFocus value={rn} onChange={e=>setRn(e.target.value)} onKeyDown={e=>e.key==="Enter"&&conf()} placeholder="Nom" style={{padding:"8px 12px",border:"1.5px solid var(--b2)",borderRadius:"var(--r1)",fontSize:13,width:160,background:"var(--bg1)",color:"var(--t1)",outline:"none"}}/><button onClick={conf} className="ba" style={{padding:"8px 16px",fontSize:12}}>OK</button><button onClick={()=>{setSl(false);setPd(null);}} className="bg2" style={{padding:"8px 12px",fontSize:12}}>✕</button></div>}<div style={{overflowX:"auto",userSelect:"none"}}><div style={{display:"grid",gridTemplateColumns:`repeat(${CO2},${CL2}px)`,border:"1px solid var(--b2)",borderRadius:"var(--r2)",background:"var(--bg1)",width:"fit-content"}} onMouseLeave={()=>{setDr(false);setSt(null);}}>{Array.from({length:RO2},(_,r)=>Array.from({length:CO2},(_,c)=>{const k=ck2(r,c),cell=plan[k];return<div key={k} onMouseDown={()=>{setDr(true);if(tool==="wall")setSt({r,c});else paint(r,c);}} onMouseUp={()=>{if(dr&&tool==="wall"&&st)fill(st.r,st.c,r,c);setDr(false);setSt(null);}} onMouseEnter={()=>{if(dr&&tool!=="wall")paint(r,c);}} style={{width:CL2,height:CL2,boxSizing:"border-box",border:"1px solid var(--bg0)",background:cell?(cell.type==="wall"?gtc("wall"):`${gtc(cell.type)}30`):"transparent",cursor:"crosshair",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9}}>{cell&&cell.type!=="wall"&&<span style={{fontSize:cell.type==="room"?7:11}}>{cell.type==="room"?(cell.label?.slice(0,4)||"▪"):PT.find(t=>t.id===cell.type)?.icon}</span>}</div>;}))}</div></div><div style={{display:"flex",flexWrap:"wrap",gap:14,marginTop:12}}>{PT.map(t=><div key={t.id} style={{display:"flex",alignItems:"center",gap:6,fontSize:11,color:"var(--t3)"}}><div style={{width:10,height:10,borderRadius:2,background:t.color}}/>{t.label}</div>)}</div></div>}

function CKC({checks,setChecks}){const tog=id=>setChecks(p=>({...p,[id]:!p[id]}));const total=Object.values(CKL).flat().length;const done=Object.values(checks).filter(Boolean).length;const pct=Math.round(done/total*100);const sc=pct===100?"var(--ok)":pct>=50?"var(--ac)":"var(--t3)";return<div><div style={{display:"flex",alignItems:"center",gap:18,marginBottom:26,background:"var(--bg1)",borderRadius:"var(--r2)",padding:"18px 22px",border:"1px solid var(--b2)"}}><div style={{flex:1}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}><span style={{fontSize:13,fontWeight:600,color:"var(--t1)"}}>Progression</span><span style={{fontSize:13,fontWeight:700,color:sc}}>{done}/{total}</span></div><div style={{background:"var(--bg0)",borderRadius:99,height:8,overflow:"hidden"}}><div style={{width:`${pct}%`,height:"100%",background:`linear-gradient(90deg,var(--ac),${sc})`,borderRadius:99,transition:"width .5s"}}/></div></div><div style={{textAlign:"center",minWidth:56}}><div style={{fontSize:28,fontWeight:800,color:sc,lineHeight:1,fontFamily:"var(--fd)"}}>{pct}%</div></div></div>{Object.entries(CKL).map(([fr,items])=><div key={fr} style={{marginBottom:22}}><h4 style={{fontSize:11,fontWeight:700,color:"var(--ac)",textTransform:"uppercase",letterSpacing:1.2,margin:"0 0 10px",fontFamily:"var(--fd)"}}>{fr}</h4><div style={{display:"flex",flexDirection:"column",gap:5}}>{items.map(it=><div key={it.id} onClick={()=>tog(it.id)} style={{display:"flex",alignItems:"center",gap:12,padding:"11px 14px",borderRadius:"var(--r1)",cursor:"pointer",background:checks[it.id]?"var(--oks)":"var(--bg1)",border:`1px solid ${checks[it.id]?"rgba(34,197,94,.25)":"var(--b2)"}`}}><div style={{width:18,height:18,borderRadius:4,border:`2px solid ${checks[it.id]?"var(--ok)":"var(--b3)"}`,background:checks[it.id]?"var(--ok)":"transparent",display:"flex",alignItems:"center",justifyContent:"center"}}>{checks[it.id]&&<CI/>}</div><span style={{fontSize:13,color:checks[it.id]?"var(--ok)":"var(--t2)",textDecoration:checks[it.id]?"line-through":"none"}}>{it.label}</span></div>)}</div></div>)}</div>}

function RN({text}){if(!text)return null;return text.split("\n").map((l,i)=>{if(l.startsWith("# "))return<h1 key={i} style={{fontSize:19,fontWeight:700,color:"var(--t1)",borderBottom:"2px solid var(--ac)",paddingBottom:10,margin:"30px 0 14px",fontFamily:"var(--fd)"}}>{l.slice(2)}</h1>;if(l.startsWith("## "))return<h2 key={i} style={{fontSize:15,fontWeight:700,color:"var(--t1)",margin:"22px 0 8px",fontFamily:"var(--fd)"}}>{l.slice(3)}</h2>;if(l.match(/^[A-Z]+:/))return<h3 key={i} style={{fontSize:13,fontWeight:600,color:"var(--ac)",margin:"14px 0 6px"}}>{l}</h3>;if(l.trim()==="")return<div key={i} style={{height:7}}/>;return<p key={i} style={{marginBottom:7,color:"var(--t2)",fontSize:13.5,lineHeight:1.75}}>{l}</p>;});}

function xPDF(n){const w=window.open("","_blank");if(!w)return;const t=TYPES_ERP[n.typeERP]||{};const tp=n.niveauxRows?.reduce((s,r)=>s+parseInt(r.effectifPublic||0),0)||"";const tpe=n.niveauxRows?.reduce((s,r)=>s+parseInt(r.effectifPersonnel||0),0)||"";const nh=(n.niveauxRows||[]).map(r=>`<tr><td>${r.niveau}</td><td>${r.activites}</td><td>${r.locaux}</td><td>${r.surface}</td><td>${r.modeCalcul}</td><td>${r.effectifPublic}</td><td>${r.effectifPersonnel}</td></tr>`).join("");const dh=(n.degagementsRows||[]).map(r=>`<tr><td>${r.niveau}</td><td>${r.effectif}</td><td>${r.effectifCumule}</td><td>${r.sortiesRegl}</td><td>${r.upRegl}</td><td>${r.sortiesPrevues}</td><td>${r.upPrevues}</td></tr>`).join("");const dfh=(n.desenfumageRows||[]).map(r=>`<tr><td>${r.local}</td><td>${r.superficie}</td><td>${r.typeDesenfumage}</td><td>${r.observations}</td></tr>`).join("");
w.document.write(`<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><title>Notice — ${n.denomination}</title><style>@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;600;700&family=Figtree:wght@400;500;600&display=swap');*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Figtree',sans-serif;color:#1e293b;font-size:10pt;line-height:1.6;padding:40px 50px}h1{font-family:'Outfit';font-size:16pt;text-align:center;margin-bottom:4px}h2{font-family:'Outfit';font-size:11pt;color:#0f172a;margin:20px 0 8px;padding:6px 12px;background:#fffbeb;border-left:3px solid #d97706}h3{font-size:10pt;color:#92400e;margin:12px 0 6px}table{width:100%;border-collapse:collapse;margin:8px 0 14px;font-size:9.5pt}th{background:#f8fafc;padding:5px 8px;text-align:left;font-weight:600;border:1px solid #d1d5db;font-size:9pt}td{padding:5px 8px;border:1px solid #d1d5db;vertical-align:top}.sub{text-align:center;font-size:9pt;color:#64748b;margin-bottom:20px}.fr{display:flex;gap:8px;margin-bottom:8px;flex-wrap:wrap}.f{flex:1;min-width:180px}.fl2{font-size:8pt;color:#64748b;text-transform:uppercase;letter-spacing:.5px;margin-bottom:2px}.fv{font-size:10pt;color:#0f172a;min-height:16px;border-bottom:1px solid #e2e8f0;padding-bottom:2px}.obs{background:#f8fafc;padding:8px 12px;border-radius:4px;margin:6px 0;border:1px solid #e2e8f0;font-size:9.5pt;color:#374151}.sig{margin-top:28px;border-top:1px solid #d1d5db;padding-top:16px}.sg{display:grid;grid-template-columns:1fr 1fr;gap:24px;margin-top:14px}.sb{text-align:center}.sli{border-bottom:1px solid #94a3b8;height:50px;margin-bottom:4px}.sla{font-size:8pt;color:#64748b}.ft{margin-top:20px;padding-top:10px;border-top:1px solid #d1d5db;display:flex;justify-content:space-between;font-size:8pt;color:#94a3b8}p{margin-bottom:5px}@media print{body{padding:20px 30px}h2{page-break-after:avoid}table{page-break-inside:avoid}}</style></head><body>
<h1>NOTICE DESCRIPTIVE DE SÉCURITÉ</h1><div class="sub">ERP du 1er groupe — Arrêté du 25/06/1980 modifié — Art. R.143-22 CCH et GE 2 §1</div>
<div class="fr"><div class="f"><div class="fl2">Dénomination</div><div class="fv">${n.denomination||""}</div></div></div>
<div class="fr"><div class="f"><div class="fl2">Adresse</div><div class="fv">${n.adresse||""}</div></div></div>
<div class="fr"><div class="f"><div class="fl2">Maîtrise d'ouvrage</div><div class="fv">${n.maitreOuvrage||""}</div></div><div class="f"><div class="fl2">Maîtrise d'œuvre</div><div class="fv">${n.maitreOeuvre||""}</div></div></div>
<div class="fr"><div class="f"><div class="fl2">Organisme contrôle</div><div class="fv">${n.organismeControle||""}</div></div><div class="f"><div class="fl2">RUS</div><div class="fv">${n.rus==="oui"?"Oui":"Non"}</div></div></div>
<h2>I — Classement (R.143-18 à R.143-21)</h2>
<div class="fr"><div class="f"><div class="fl2">Type</div><div class="fv">${n.typeERP} — ${t.desc||""}</div></div><div class="f"><div class="fl2">Catégorie</div><div class="fv">${n.categorie}</div></div></div>
<table><thead><tr><th>Niveau</th><th>Activités</th><th>Locaux</th><th>Surface</th><th>Mode calcul</th><th>Eff. public</th><th>Eff. pers.</th></tr></thead><tbody>${nh}<tr><td colspan="5" style="text-align:right;font-weight:600">TOTAUX</td><td style="font-weight:700">${tp}</td><td style="font-weight:700">${tpe}</td></tr></tbody></table>
<h2>II — Construction (CO 1 à CO 60)</h2>
<h3>Desserte (CO 1-5)</h3>${n.desserte_obs?`<div class="obs">${n.desserte_obs}</div>`:""}
<h3>Isolement (CO 6-10)</h3><div class="fr"><div class="f"><div class="fl2">Vis-à-vis</div><div class="fv">${n.isolement_visavis||""}</div></div><div class="f"><div class="fl2">Contigu</div><div class="fv">${n.isolement_contigu||""}</div></div><div class="f"><div class="fl2">Superposé</div><div class="fv">${n.isolement_superpose||""}</div></div></div>${n.isolement_obs?`<div class="obs">${n.isolement_obs}</div>`:""}
<h3>Résistance au feu (CO 11-15)</h3><div class="fr"><div class="f"><div class="fl2">Structure</div><div class="fv">${n.resistanceFeu_structure||""}</div></div><div class="f"><div class="fl2">Planchers</div><div class="fv">${n.resistanceFeu_planchers||""}</div></div></div>${n.resistanceFeu_obs?`<div class="obs">${n.resistanceFeu_obs}</div>`:""}
<h3>Distribution (CO 23-26)</h3><div class="fr"><div class="f"><div class="fl2">Type</div><div class="fv">${n.distribution_type||""}</div></div></div>${n.distribution_obs?`<div class="obs">${n.distribution_obs}</div>`:""}
<h3>EAS / PMR (GN 8-10, CO 57-60)</h3><p>EAS : ${n.eas==="oui"?"Oui":"Non"} | Solution équivalente : ${n.solutionEquivalente==="oui"?"Oui":"Non"}</p>${n.eas_obs?`<div class="obs">${n.eas_obs}</div>`:""}
<h3>Locaux à risques (CO 27-29)</h3><p>Présence : ${n.locauxRisques==="oui"?"Oui":"Non"}</p>${n.locauxRisques_obs?`<div class="obs">${n.locauxRisques_obs}</div>`:""}
<h3>Dégagements (CO 34-56)</h3><table><thead><tr><th>Niveau</th><th>Effectif</th><th>Eff. cumulé</th><th>Sorties régl.</th><th>UP régl.</th><th>Sorties prév.</th><th>UP prév.</th></tr></thead><tbody>${dh}</tbody></table>
<h2>III — Aménagements (AM 1-19)</h2><table><thead><tr><th></th><th>Locaux/dégagements</th><th>Escaliers encloisonnés</th></tr></thead><tbody><tr><td>Murs</td><td>${n.revetements_murs_locaux||""}</td><td>${n.revetements_murs_escaliers||""}</td></tr><tr><td>Sol</td><td>${n.revetements_sol_locaux||""}</td><td>${n.revetements_sol_escaliers||""}</td></tr><tr><td>Plafond</td><td>${n.revetements_plafond_locaux||""}</td><td>${n.revetements_plafond_escaliers||""}</td></tr></tbody></table>${n.amenagements_obs?`<div class="obs">${n.amenagements_obs}</div>`:""}
<h2>IV — Désenfumage (DF 1-10)</h2><table><thead><tr><th>Local</th><th>Superficie</th><th>Type</th><th>Observations</th></tr></thead><tbody>${dfh}</tbody></table>
<h2>V — Chauffage (CH 1-58)</h2><div class="fr"><div class="f"><div class="fl2">Chaufferie</div><div class="fv">${n.chaufferie_type||""}</div></div><div class="f"><div class="fl2">Énergie</div><div class="fv">${n.energie||""}</div></div></div>${n.chauffage_obs?`<div class="obs">${n.chauffage_obs}</div>`:""}
<h2>VI — Gaz (GZ 1-30)</h2>${n.gaz_obs?`<div class="obs">${n.gaz_obs}</div>`:"<p>—</p>"}
<h2>VII — Électricité (EL 1-23)</h2>${n.elec_obs?`<div class="obs">${n.elec_obs}</div>`:"<p>—</p>"}
<h2>VIII — Éclairage (EC 1-12)</h2>${n.eclairage_obs?`<div class="obs">${n.eclairage_obs}</div>`:"<p>—</p>"}
<h2>IX — Ascenseurs (AS 1-11)</h2>${n.ascenseurs_obs?`<div class="obs">${n.ascenseurs_obs}</div>`:"<p>—</p>"}
<h2>X — Cuisson (GC 1-20)</h2><div class="fr"><div class="f"><div class="fl2">Puissance ≥ 20 kW</div><div class="fv">${n.cuisson_puissance||""}</div></div></div>${n.cuisson_obs?`<div class="obs">${n.cuisson_obs}</div>`:""}
<h2>XI — Moyens de secours (MS 1-74)</h2>
<table><tbody><tr><td>Poteaux incendie</td><td>Nbre : ${n.poteaux_nombre||"—"}</td><td>Débit : ${n.poteaux_debit||"—"} m³/h</td></tr><tr><td>Bouches incendie</td><td>Nbre : ${n.bouches_nombre||"—"}</td><td>Débit : ${n.bouches_debit||"—"} m³/h</td></tr><tr><td>Réserve</td><td colspan="2">${n.reserve_contenance||"—"} m³</td></tr><tr><td>RIA</td><td colspan="2">Nbre : ${n.ria_nombre||"—"}</td></tr><tr><td>Extincteurs</td><td colspan="2">${n.extincteurs_desc||"—"}</td></tr><tr><td>Ext. adaptés</td><td colspan="2">${n.extincteurs_adaptes||"—"}</td></tr><tr><td>Autres</td><td colspan="2">${n.autres_moyens||"—"}</td></tr></tbody></table>
<h3>SSI (MS 53-60)</h3><p>Catégorie : ${n.ssi_categorie||"—"} | Détection : ${n.ssi_detection_locaux||"—"}</p>
<h3>Alarme (MS 61-67)</h3><p>Type : ${n.alarme_type||"—"} | Handicap : ${n.alarme_handicap||"—"}</p>
<h2>XII — Dérogations (R.143-13, GN 4)</h2><p>${n.derogation==="oui"?"Oui — Nombre : "+(n.derogation_nombre||""):"Non"}</p>${n.derogation_details?`<div class="obs">${n.derogation_details}</div>`:""}
<div class="sig"><p>Je soussigné, <strong>${n.signataire||n.maitreOuvrage||""}</strong>, Maître d'ouvrage, m'engage à respecter les dispositions de la présente notice et les règles générales de construction (CCH).</p><div class="sg"><div><p>Date : ${new Date().toLocaleDateString("fr-FR")}</p></div><div class="sb"><div class="sli"></div><div class="sla">Signature du maître d'ouvrage</div></div></div></div>
<div class="ft"><span>Prev'Notice — Notice descriptive de sécurité ERP</span><span>${new Date().toLocaleDateString("fr-FR")}</span></div>
<${"script"}>window.onload=()=>window.print()</${"script"}></body></html>`);w.document.close();}

function bPrompt(f){const t=TYPES_ERP[f.typeERP]||{};const tp=f.niveauxRows?.reduce((s,r)=>s+parseInt(r.effectifPublic||0),0)||0;
return`Expert sécurité incendie ERP France. Pour cet établissement, génère les observations techniques pour chaque section de la notice (art. GE2, arrêté 25/06/1980).

ÉTAB: ${f.denomination} | Type ${f.typeERP} (${t.desc||""}) | Cat. ${f.categorie}
Adresse: ${f.adresse} | Eff. public: ${tp} | Eff. personnel: ${f.niveauxRows?.reduce((s,r)=>s+parseInt(r.effectifPersonnel||0),0)||0}
Niveaux: ${f.niveauxRows?.map(r=>r.niveau+": "+r.locaux).join(", ")||""}
Structure: ${f.resistanceFeu_structure}, Planchers: ${f.resistanceFeu_planchers}
Distribution: ${f.distribution_type} | EAS: ${f.eas} | Locaux risques: ${f.locauxRisques}
Chaufferie: ${f.chaufferie_type} | Énergie: ${f.energie}
SSI: ${f.ssi_categorie} | Alarme: ${f.alarme_type} | Cuisson: ${f.cuisson_puissance}

Format STRICT (une obs par ligne, 2-4 phrases techniques, cite les articles):
DESSERTE: [obs desserte/accès pompiers]
ISOLEMENT: [obs isolement tiers]
RESISTANCE: [obs résistance feu]
DISTRIBUTION: [obs distribution intérieure]
EAS: [obs évacuation PMR]
RISQUES: [obs locaux à risques]
CONDUITS: [obs conduits/gaines]
AMENAGEMENTS: [obs aménagements intérieurs]
CHAUFFAGE: [obs chauffage/ventilation]
GAZ: [obs gaz]
ELECTRICITE: [obs électricité]
ECLAIRAGE: [obs éclairage sécurité]
ASCENSEURS: [obs ou Sans objet]
CUISSON: [obs ou Sans objet]
SURVEILLANCE: [obs surveillance/service sécurité]`;}

// ━━━ LAYOUT ━━━
function Side({goNew,navI,view,setView,etabs,showNE,neN,setNeN,neV,setNeV,addEtab,setShowNE,fEtab,setFEtab,collapsed,setCollapsed}){return<div style={{width:collapsed?62:230,background:"var(--bg1)",borderRight:"1px solid var(--b1)",display:"flex",flexDirection:"column",minHeight:"100vh",position:"sticky",top:0,zIndex:10,transition:"width .25s"}} className="do"><div style={{padding:collapsed?"18px 12px":"26px 20px 22px",borderBottom:"1px solid var(--b1)",display:"flex",alignItems:"center",justifyContent:"space-between"}}>{collapsed?<div style={{width:38,height:38,background:"linear-gradient(135deg,#d97706,#f59e0b)",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,margin:"0 auto"}}>🛡️</div>:<div style={{display:"flex",alignItems:"center",gap:11}}><div style={{width:38,height:38,background:"linear-gradient(135deg,#d97706,#f59e0b)",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>🛡️</div><div><div style={{fontWeight:700,fontSize:15,color:"var(--t1)",fontFamily:"var(--fd)"}}>Prev'Notice</div><div style={{fontSize:10,color:"var(--t3)"}}>Sécurité ERP</div></div></div>}<button onClick={()=>setCollapsed(!collapsed)} style={{background:"none",border:"none",color:"var(--t3)",cursor:"pointer",fontSize:14,padding:4,flexShrink:0}}>{collapsed?"▸":"◂"}</button></div><nav style={{padding:collapsed?"8px 6px":"16px 12px"}}><button onClick={goNew} style={{width:"100%",display:"flex",alignItems:"center",gap:10,padding:collapsed?"10px":"11px 14px",borderRadius:"var(--r2)",border:"none",cursor:"pointer",marginBottom:12,background:"linear-gradient(135deg,#d97706,#f59e0b)",color:"#000",fontFamily:"var(--fb)",fontSize:collapsed?0:13.5,fontWeight:600,justifyContent:collapsed?"center":"flex-start"}}><span style={{fontSize:collapsed?18:14}}>✚</span>{!collapsed&&" Nouvelle notice"}</button>{navI.map(it=><button key={it.id} onClick={()=>setView(it.id)} style={{width:"100%",display:"flex",alignItems:"center",gap:10,padding:collapsed?"10px":"10px 14px",borderRadius:"var(--r1)",border:"none",cursor:"pointer",marginBottom:3,background:view===it.id?"var(--bg3)":"transparent",color:view===it.id?"var(--t1)":"var(--t3)",fontFamily:"var(--fb)",fontSize:collapsed?0:13.5,fontWeight:view===it.id?600:400,justifyContent:collapsed?"center":"flex-start"}}><span style={{fontSize:collapsed?18:14}}>{it.icon}</span>{!collapsed&&it.label}</button>)}</nav>{!collapsed&&<div style={{padding:"16px 12px",borderTop:"1px solid var(--b1)",maxHeight:"35vh",overflowY:"auto"}}><div style={{fontSize:10,fontWeight:700,color:"var(--t3)",textTransform:"uppercase",letterSpacing:1.2,marginBottom:10}}>Établissements</div>{etabs.length===0&&!showNE&&<div style={{fontSize:11.5,color:"var(--t3)",opacity:.7}}>Aucun</div>}{etabs.map(e=><div key={e.id} onClick={()=>{setFEtab(e.id);setView("notices");}} style={{padding:"7px 10px",borderRadius:"var(--r1)",cursor:"pointer",background:fEtab===e.id?"var(--bg3)":"transparent",marginBottom:2}}><div style={{fontSize:12.5,color:fEtab===e.id?"var(--t1)":"var(--t3)"}}>{e.nom}</div></div>)}{showNE?<div style={{display:"flex",flexDirection:"column",gap:6,marginTop:8}}><input autoFocus value={neN} onChange={e=>setNeN(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addEtab()} placeholder="Nom" style={{padding:"7px 10px",borderRadius:"var(--r1)",border:"1px solid var(--b2)",background:"var(--bg1)",color:"var(--t1)",fontSize:12,outline:"none"}}/><input value={neV} onChange={e=>setNeV(e.target.value)} placeholder="Ville" style={{padding:"7px 10px",borderRadius:"var(--r1)",border:"1px solid var(--b2)",background:"var(--bg1)",color:"var(--t1)",fontSize:12,outline:"none"}}/><div style={{display:"flex",gap:6}}><button onClick={addEtab} style={{flex:1,padding:6,background:"var(--ac)",color:"#000",border:"none",borderRadius:"var(--r1)",fontSize:12,cursor:"pointer",fontWeight:600}}>OK</button><button onClick={()=>setShowNE(false)} style={{padding:"6px 8px",background:"var(--bg3)",border:"none",borderRadius:"var(--r1)",fontSize:12,cursor:"pointer",color:"var(--t3)"}}>✕</button></div></div>:<button onClick={()=>setShowNE(true)} style={{width:"100%",padding:"7px 10px",borderRadius:"var(--r1)",border:"1px dashed var(--b2)",background:"transparent",color:"var(--t3)",fontSize:12,cursor:"pointer",marginTop:6}}>+ Ajouter</button>}</div>}</div>}
function MobH({title,back,goNew}){return<div style={{background:"var(--bg1)",borderBottom:"1px solid var(--b1)",padding:"12px 16px",display:"flex",alignItems:"center",gap:12,position:"sticky",top:0,zIndex:100}}>{back&&<button onClick={back} style={{background:"transparent",border:"none",color:"var(--t3)",cursor:"pointer",fontSize:16}}>←</button>}<div style={{display:"flex",alignItems:"center",gap:8}}><div style={{width:30,height:30,background:"linear-gradient(135deg,#d97706,#f59e0b)",borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center",fontSize:15}}>🛡️</div><span style={{fontWeight:700,color:"var(--t1)",fontSize:14,fontFamily:"var(--fd)"}}>{title||"Prev'Notice"}</span></div><button onClick={goNew} style={{marginLeft:"auto",padding:"7px 14px",background:"linear-gradient(135deg,#d97706,#f59e0b)",color:"#000",border:"none",borderRadius:"var(--r1)",fontSize:12,fontWeight:600,cursor:"pointer"}}>+</button></div>}
function Lay({children,title,back,sidebarProps,ts,rm,goNew}){return<div style={{display:"flex",minHeight:"100vh",background:"var(--bg0)"}}><style>{CSS}</style><Side {...sidebarProps}/><div style={{flex:1,display:"flex",flexDirection:"column",minWidth:0}}><div style={{display:"none"}} className="mhw"><MobH title={title} back={back} goNew={goNew}/></div><style>{`@media(max-width:768px){.mhw{display:block!important}}`}</style><div style={{flex:1,padding:"30px 36px",maxWidth:1100,width:"100%"}} className="mp">{children}</div></div><Toasts ts={ts} rm={rm}/></div>}

// ━━━ APP ━━━
export default function PrevNotice(){
  const[notices,setNotices]=useState([]);const[etabs,setEtabs]=useState([]);const[view,setView]=useState("dashboard");const[step,setStep]=useState(1);const[form,setForm]=useState(EF);const[loading,setLoading]=useState(false);const[genStep,setGenStep]=useState(0);const[error,setError]=useState(null);const[open,setOpen]=useState(null);const[tab,setTab]=useState("notice");const[plan,setPlan]=useState({});const[chk,setChk]=useState({});const[fEtab,setFEtab]=useState("all");const[sq,setSq]=useState("");const[showNE,setShowNE]=useState(false);const[neN,setNeN]=useState("");const[neV,setNeV]=useState("");const[ready,setReady]=useState(false);const[hasDraft,setHasDraft]=useState(false);const[dirty,setDirty]=useState(false);const[collapsed,setCollapsed]=useState(false);
  const{ts,add,rm}=useToast();const dtRef=useRef(null);

  useEffect(()=>{(async()=>{try{const[n,e,c,d]=await Promise.all([sGet("sn:notices",[]),sGet("sn:etabs",[]),sGet("sn:checks",{}),sGet("sn:draft",null)]);setNotices(n);setEtabs(e);setChk(c);if(d?.denomination)setHasDraft(true);}catch{}setReady(true);})();},[]);
  useEffect(()=>{if(ready)sSet("sn:notices",notices);},[notices,ready]);
  useEffect(()=>{if(ready)sSet("sn:etabs",etabs);},[etabs,ready]);
  useEffect(()=>{if(ready)sSet("sn:checks",chk);},[chk,ready]);
  useEffect(()=>{if(view!=="form"||!dirty)return;if(dtRef.current)clearTimeout(dtRef.current);dtRef.current=setTimeout(()=>sSet("sn:draft",{...form,_step:step,_t:Date.now()}),2000);return()=>{if(dtRef.current)clearTimeout(dtRef.current);};},[form,step,view,dirty]);

  const upd=(f,v)=>{setForm(p=>({...p,[f]:v}));setDirty(true);};
  const addEtab=()=>{if(!neN.trim())return;setEtabs(p=>[...p,{id:"e-"+Date.now(),nom:neN.trim(),ville:neV.trim()}]);setNeN("");setNeV("");setShowNE(false);add("Établissement ajouté","s");};
  const gChk=id=>chk[id]||{};const sChk=id=>fn=>setChk(p=>({...p,[id]:typeof fn==="function"?fn(p[id]||{}):fn}));
  const tryNext=()=>{const e=VAL[step]?.(form);if(e){setError(e);add(e,"e");return;}setError(null);setStep(step+1);};
  const goNew=()=>{setForm(EF);setStep(1);setError(null);setDirty(false);setView("form");};
  const restDraft=async()=>{try{const d=await sGet("sn:draft",null);if(d){const{_step,_t,...fd}=d;setForm(fd);setStep(_step||1);setView("form");setDirty(true);setHasDraft(false);add("Brouillon restauré","i");}}catch{}};
  const clrDraft=async()=>{try{await sSet("sn:draft",null);}catch{}setHasDraft(false);};

  const GS=["Analyse…","Vérification…","Rédaction…","Mise en forme…","Finalisation…"];
  const gen=async(r=0)=>{setLoading(true);setError(null);setGenStep(0);const adv=()=>new Promise(res=>{setTimeout(()=>{setGenStep(s=>s+1);res();},1200);});
    try{adv();const res=await fetch("/api/generate",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:8096,messages:[{role:"user",content:bPrompt(form)}]})});adv();const data=await res.json();if(data.error)throw new Error(data.error.message);await adv();const txt=data.content?.map(i=>i.text||"").join("\n")||"";
      const obs={};txt.split("\n").forEach(l=>{const m=l.match(/^(\w+):\s*(.+)/);if(m)obs[m[1]]=m[2];});
      const filled={...form,desserte_obs:obs.DESSERTE||form.desserte_obs,isolement_obs:obs.ISOLEMENT||form.isolement_obs,resistanceFeu_obs:obs.RESISTANCE||form.resistanceFeu_obs,distribution_obs:obs.DISTRIBUTION||form.distribution_obs,eas_obs:obs.EAS||form.eas_obs,locauxRisques_obs:obs.RISQUES||form.locauxRisques_obs,conduits_obs:obs.CONDUITS||form.conduits_obs,amenagements_obs:obs.AMENAGEMENTS||form.amenagements_obs,chauffage_obs:obs.CHAUFFAGE||form.chauffage_obs,gaz_obs:obs.GAZ||form.gaz_obs,elec_obs:obs.ELECTRICITE||form.elec_obs,eclairage_obs:obs.ECLAIRAGE||form.eclairage_obs,ascenseurs_obs:obs.ASCENSEURS||form.ascenseurs_obs,cuisson_obs:obs.CUISSON||form.cuisson_obs,surveillance_obs:obs.SURVEILLANCE||form.surveillance_obs,noticeText:txt,id:Date.now().toString(),savedAt:new Date().toLocaleDateString("fr-FR"),planData:{}};
      await adv();setNotices(p=>[filled,...p]);setOpen(filled);setPlan({});setTab("notice");setView("detail");setDirty(false);sSet("sn:draft",null);setHasDraft(false);setGenStep(5);add("Notice générée !","s");
    }catch(e){if(r<2){add(`Tentative ${r+2}/3…`,"i");setTimeout(()=>gen(r+1),1500);return;}setError(`Erreur : ${e.message}`);add("Échec","e");}finally{if(r>=2||r===0)setLoading(false);}};

  const del=id=>{setNotices(p=>p.filter(n=>n.id!==id));if(open?.id===id)setView("dashboard");add("Supprimée","i");};
  const savePlan=()=>{setNotices(p=>p.map(n=>n.id===open.id?{...n,planData:plan}:n));setOpen(p=>({...p,planData:plan}));add("Plan sauvegardé","s");};
  const fNotices=useMemo(()=>{let l=notices;if(fEtab!=="all")l=l.filter(n=>n.etablissementId===fEtab);if(sq.trim()){const q=sq.toLowerCase();l=l.filter(n=>(n.denomination||"").toLowerCase().includes(q)||(n.adresse||"").toLowerCase().includes(q));}return l;},[notices,fEtab,sq]);
  const stats=useMemo(()=>({total:notices.length,month:notices.filter(n=>{if(!n.savedAt)return false;const[,m,y]=n.savedAt.split("/");const now=new Date();return parseInt(m)===now.getMonth()+1&&parseInt(y)===now.getFullYear();}).length,byType:Object.entries(TYPES_ERP).map(([code,{icon,desc}])=>({code,icon,label:desc,count:notices.filter(n=>n.typeERP===code).length,full:code})).filter(x=>x.count>0).sort((a,b)=>b.count-a.count),etabs:etabs.length}),[notices,etabs]);

  if(!ready)return<div style={{display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh",background:"var(--bg0)"}}><style>{CSS}</style><div><div style={{width:24,height:24,border:"3px solid var(--b2)",borderTop:"3px solid var(--ac)",borderRadius:"50%",animation:"sp .8s linear infinite",margin:"0 auto 16px"}}/><div style={{color:"var(--t3)",fontSize:13}}>Chargement…</div></div></div>;

  const navI=[{id:"dashboard",icon:"◻",label:"Dashboard"},{id:"notices",icon:"📋",label:"Notices"}];
  const sidebarProps={goNew,navI,view,setView,etabs,showNE,neN,setNeN,neV,setNeV,addEtab,setShowNE,fEtab,setFEtab,collapsed,setCollapsed};
  const layoutProps={sidebarProps,ts,rm,goNew};
  const navBtns=(back)=><div style={{display:"flex",gap:10,justifyContent:"flex-end",marginTop:20}}>{back&&<button className="bg2" onClick={()=>{setError(null);setStep(step-1);}}>← Retour</button>}{step<7&&<button className="ba" onClick={tryNext}>Suivant →</button>}</div>;

  // DASHBOARD
  if(view==="dashboard")return<Lay {...layoutProps} title="Dashboard"><div className="fi">
    <div style={{marginBottom:32}}><h1 style={{fontSize:28,fontWeight:800,color:"var(--t1)",fontFamily:"var(--fd)"}}>Dashboard</h1><p style={{color:"var(--t3)",fontSize:14}}>Notices descriptives de sécurité ERP</p></div>
    {hasDraft&&<div style={{display:"flex",alignItems:"center",gap:14,padding:"14px 20px",background:"rgba(245,158,11,.06)",border:"1px solid rgba(245,158,11,.15)",borderRadius:"var(--r2)",marginBottom:20}}><span className="db">⏳ Brouillon</span><span style={{color:"var(--t2)",fontSize:13,flex:1}}>Formulaire en cours.</span><button onClick={restDraft} className="ba" style={{padding:"7px 16px",fontSize:12}}>Reprendre</button><button onClick={clrDraft} className="bg2" style={{padding:"7px 12px",fontSize:12}}>Supprimer</button></div>}
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:16,marginBottom:30}} className="sg">{[{l:"Notices",v:stats.total,c:"var(--ac)"},{l:"Ce mois",v:stats.month,c:"#fb923c"},{l:"Établissements",v:stats.etabs,c:"#22d3ee"},{l:"Types",v:stats.byType.length,c:"#c084fc"}].map((s,i)=><div key={i} className="card" style={{padding:"20px 22px"}}><div style={{fontSize:11,fontWeight:600,color:"var(--t3)",textTransform:"uppercase",letterSpacing:.8,marginBottom:10}}>{s.l}</div><div style={{fontSize:32,fontWeight:800,color:s.c,fontFamily:"var(--fd)"}}>{s.v}</div></div>)}</div>
    {notices.length===0?<div style={{textAlign:"center",padding:"48px 24px",border:"1px dashed var(--b2)",borderRadius:"var(--r3)"}}><div style={{fontSize:48,marginBottom:16}}>🛡️</div><h2 style={{fontSize:22,fontWeight:800,color:"var(--t1)",fontFamily:"var(--fd)",marginBottom:8}}>Bienvenue sur Prev'Notice</h2><p style={{color:"var(--t3)",fontSize:14,maxWidth:460,margin:"0 auto 8px"}}>Générez des notices descriptives de sécurité ERP au format officiel (art. GE2).</p><div className="ob-steps"><div className="ob-s"><div className="ob-n">1</div><div style={{fontSize:22,marginBottom:8}}>📝</div><div style={{fontWeight:600,color:"var(--t1)",fontSize:13,marginBottom:4}}>Formulaire officiel</div><div style={{fontSize:12,color:"var(--t3)"}}>7 sections conformes R.143-22 CCH</div></div><div className="ob-s"><div className="ob-n">2</div><div style={{fontSize:22,marginBottom:8}}>⚡</div><div style={{fontWeight:600,color:"var(--t1)",fontSize:13,marginBottom:4}}>Observations auto</div><div style={{fontSize:12,color:"var(--t3)"}}>Champs techniques complétés</div></div><div className="ob-s"><div className="ob-n">3</div><div style={{fontSize:22,marginBottom:8}}>🖨️</div><div style={{fontWeight:600,color:"var(--t1)",fontSize:13,marginBottom:4}}>PDF officiel</div><div style={{fontSize:12,color:"var(--t3)"}}>Format administration</div></div></div><button className="ba" onClick={goNew} style={{marginTop:28,padding:"13px 32px",fontSize:15}}>+ Créer</button></div>:
    <div style={{display:"flex",flexDirection:"column",gap:8}}>{notices.slice(0,6).map(n=>{const t=TYPES_ERP[n.typeERP]||{};return<div key={n.id} className="nr" onClick={()=>{setOpen(n);setPlan(n.planData||{});setTab("notice");setView("detail");}}><div style={{width:40,height:40,background:"var(--acs)",borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>{t.icon||"🏢"}</div><div style={{flex:1,minWidth:0}}><div style={{fontSize:14,fontWeight:600,color:"var(--t1)"}}>{n.denomination}</div><div style={{fontSize:12,color:"var(--t3)"}}>Type {n.typeERP} · Cat. {n.categorie}</div></div><div style={{fontSize:10,color:"var(--t3)"}}>  {n.savedAt}</div></div>})}</div>}
  </div></Lay>;

  // NOTICES LIST
  if(view==="notices")return<Lay {...layoutProps} title="Notices"><div className="fi">
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}} className="ms"><div><h1 style={{fontSize:24,fontWeight:800,color:"var(--t1)",fontFamily:"var(--fd)"}}>Notices</h1><p style={{color:"var(--t3)",fontSize:13}}>{fNotices.length} notice{fNotices.length!==1?"s":""}</p></div><button className="ba" onClick={goNew}>+ Nouvelle</button></div>
    <div style={{marginBottom:20}}><SB v={sq} onChange={setSq} ph="Rechercher…"/></div>
    {fNotices.length===0?<Empty icon="🔍" title="Aucun résultat" action={goNew} al="Créer"/>:<div style={{display:"flex",flexDirection:"column",gap:10}}>{fNotices.map(n=>{const t=TYPES_ERP[n.typeERP]||{};return<div key={n.id} className="nr" onClick={()=>{setOpen(n);setPlan(n.planData||{});setTab("notice");setView("detail");}}><div style={{width:44,height:44,background:"var(--acs)",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>{t.icon||"🏢"}</div><div style={{flex:1,minWidth:0}}><div style={{fontSize:15,fontWeight:600,color:"var(--t1)"}}>{n.denomination}</div><div style={{fontSize:12,color:"var(--t3)"}}>Type {n.typeERP} · Cat. {n.categorie} · {n.adresse}</div></div><div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:6,flexShrink:0}}><div style={{fontSize:11,color:"var(--t3)"}}>{n.savedAt}</div><div style={{display:"flex",gap:6}}><button onClick={e=>{e.stopPropagation();xPDF(n);}} className="bg2" style={{padding:"4px 10px",fontSize:11}}>PDF</button><button onClick={e=>{e.stopPropagation();if(window.confirm("Supprimer ?"))del(n.id);}} className="bg2" style={{padding:"4px 10px",fontSize:11,color:"var(--dg)"}}>✕</button></div></div></div>})}</div>}
  </div></Lay>;

  // FORM 7 STEPS
  if(view==="form")return<Lay {...layoutProps} title="Nouvelle notice" back={()=>{if(dirty&&!window.confirm("Quitter ?"))return;setView("dashboard");}}><div className="fi">
    <div style={{display:"flex",alignItems:"center",marginBottom:24,overflowX:"auto"}}>{STP.map((s,i)=><div key={i} style={{display:"flex",alignItems:"center",flex:i<STP.length-1?1:"auto"}}><div style={{display:"flex",alignItems:"center",gap:6,cursor:i+1<step?"pointer":"default",whiteSpace:"nowrap"}} onClick={()=>{if(i+1<step)setStep(i+1);}}><div className={`sd ${i+1===step?"sd-a":i+1<step?"sd-d":"sd-i"}`}>{i+1<step?"✓":i+1}</div><span style={{fontSize:11,color:i+1===step?"var(--ac)":i+1<step?"var(--ok)":"var(--t3)",fontWeight:i+1===step?700:400}} className="do">{s}</span></div>{i<STP.length-1&&<div style={{flex:1,height:1,background:i+1<step?"rgba(34,197,94,.2)":"var(--b1)",margin:"0 8px",minWidth:8}}/>}</div>)}{dirty&&<span className="db" style={{marginLeft:8,flexShrink:0}}>💾</span>}</div>
    <div className="card" style={{padding:0,overflow:"hidden"}}><div style={{padding:"14px 22px",borderBottom:"1px solid var(--b1)",background:"var(--bg1)"}}><h2 style={{margin:0,fontSize:14,fontWeight:700,color:"var(--t1)",fontFamily:"var(--fd)"}}>Étape {step}/{STP.length} — {STP[step-1]}</h2></div><div style={{padding:24}}>
    {error&&<div style={{background:"rgba(239,68,68,.08)",border:"1px solid rgba(239,68,68,.25)",borderRadius:"var(--r1)",padding:"11px 15px",marginBottom:14,color:"#fca5a5",fontSize:13}}>{error}</div>}

    {step===1&&<div className="si"><div className="sl">Identification</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:14}} className="gr"><SI label="Dénomination" field="denomination" placeholder="Nom de l'établissement" form={form} upd={upd} req span={2}/><SI label="Adresse" field="adresse" placeholder="Adresse complète" form={form} upd={upd} req span={2}/><SI label="Maîtrise d'ouvrage" field="maitreOuvrage" form={form} upd={upd}/><SI label="Maîtrise d'œuvre" field="maitreOeuvre" form={form} upd={upd}/><SI label="Organisme de contrôle" field="organismeControle" form={form} upd={upd}/><SI label="Missions confiées" field="missionsConfiees" form={form} upd={upd} tip="L, HS, SEI…"/></div><Rad label="Responsable Unique de Sécurité (R.143-21)" field="rus" form={form} upd={upd}/><div className="sl" style={{marginTop:20}}>Contact</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:14}} className="g3"><SI label="Nom" field="contactNom" form={form} upd={upd}/><SI label="Qualité" field="contactQualite" form={form} upd={upd}/><SI label="Téléphone" field="contactTel" form={form} upd={upd}/></div><div className="sl" style={{marginTop:20}}>Projet</div><OBS label="Activités" field="descriptifActivites" form={form} upd={upd} placeholder="Activités envisagées…"/><OBS label="Travaux" field="descriptifTravaux" form={form} upd={upd} placeholder="Nature des travaux…"/>{navBtns(false)}</div>}

    {step===2&&<div className="si"><div className="sl">Classement (R.143-18 à R.143-21)</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:20}} className="gr"><div className="fl"><label>Type ERP <span style={{color:"var(--dg)"}}>*</span></label><select value={form.typeERP} onChange={e=>upd("typeERP",e.target.value)}><option value="">Choisir</option>{Object.entries(TYPES_ERP).map(([c,{icon,desc}])=><option key={c} value={c}>{icon} {c} — {desc}</option>)}</select></div><div className="fl"><label>Catégorie <span style={{color:"var(--dg)"}}>*</span></label><select value={form.categorie} onChange={e=>upd("categorie",e.target.value)}><option value="">Choisir</option><option value="1">1re (&gt;1500)</option><option value="2">2e (701-1500)</option><option value="3">3e (301-700)</option><option value="4">4e (≤300)</option><option value="5">5e</option></select></div></div><div className="sl">Effectifs par niveau</div><NivT rows={form.niveauxRows} upd={upd}/>{navBtns(true)}</div>}

    {step===3&&<div className="si"><div className="sl">Construction (CO 1 à CO 60)</div><h3 style={{fontSize:12,color:"var(--ac)",margin:"0 0 10px"}}>Desserte (CO 1-5)</h3><OBS label="Observations" field="desserte_obs" form={form} upd={upd} placeholder="Voies d'accès, largeurs…"/><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>Isolement (CO 6-10)</h3><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:14,marginBottom:10}} className="gr"><SI label="Vis-à-vis" field="isolement_visavis" form={form} upd={upd}/><SI label="Contigu" field="isolement_contigu" form={form} upd={upd}/><SI label="Superposé" field="isolement_superpose" form={form} upd={upd}/><SI label="Toitures" field="isolement_toitures" form={form} upd={upd}/></div><OBS label="Observations" field="isolement_obs" form={form} upd={upd}/><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>Résistance au feu (CO 11-15)</h3><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:10}} className="gr"><SI label="Structure" field="resistanceFeu_structure" placeholder="Ex : R 60" form={form} upd={upd} tip="Degré résistance structure porteuse"/><SI label="Planchers" field="resistanceFeu_planchers" placeholder="Ex : REI 60" form={form} upd={upd}/></div><OBS label="Observations" field="resistanceFeu_obs" form={form} upd={upd}/><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>Distribution (CO 23-26)</h3><SI label="Type" field="distribution_type" placeholder="Cloisonnement, secteurs…" form={form} upd={upd}/><OBS label="Observations" field="distribution_obs" form={form} upd={upd}/><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>PMR (GN 8-10, CO 57-60)</h3><Rad label="EAS" field="eas" form={form} upd={upd}/><Rad label="Solution équivalente" field="solutionEquivalente" form={form} upd={upd}/><OBS label="Observations" field="eas_obs" form={form} upd={upd}/><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>Locaux à risques (CO 27-29)</h3><Rad label="Présence" field="locauxRisques" form={form} upd={upd}/><OBS label="Observations" field="locauxRisques_obs" form={form} upd={upd}/><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>Dégagements (CO 34-56)</h3><DegT rows={form.degagementsRows} upd={upd}/>{navBtns(true)}</div>}

    {step===4&&<div className="si"><div className="sl">Aménagements (AM 1-19)</div><table className="dt"><thead><tr><th></th><th>Locaux/dégagements</th><th>Escaliers</th></tr></thead><tbody><tr><td style={{fontWeight:600,fontSize:11,color:"var(--t2)"}}>Murs</td><td><input value={form.revetements_murs_locaux} onChange={e=>upd("revetements_murs_locaux",e.target.value)} placeholder="M1, B-s2,d0…"/></td><td><input value={form.revetements_murs_escaliers} onChange={e=>upd("revetements_murs_escaliers",e.target.value)}/></td></tr><tr><td style={{fontWeight:600,fontSize:11,color:"var(--t2)"}}>Sol</td><td><input value={form.revetements_sol_locaux} onChange={e=>upd("revetements_sol_locaux",e.target.value)} placeholder="M3, Dfl-s1…"/></td><td><input value={form.revetements_sol_escaliers} onChange={e=>upd("revetements_sol_escaliers",e.target.value)}/></td></tr><tr><td style={{fontWeight:600,fontSize:11,color:"var(--t2)"}}>Plafond</td><td><input value={form.revetements_plafond_locaux} onChange={e=>upd("revetements_plafond_locaux",e.target.value)} placeholder="M0, A2-s1,d0…"/></td><td><input value={form.revetements_plafond_escaliers} onChange={e=>upd("revetements_plafond_escaliers",e.target.value)}/></td></tr></tbody></table><OBS label="Observations" field="amenagements_obs" form={form} upd={upd}/><div className="sl" style={{marginTop:24}}>Désenfumage (DF 1-10)</div><DesT rows={form.desenfumageRows} upd={upd}/>{navBtns(true)}</div>}

    {step===5&&<div className="si"><div className="sl">Chauffage (CH 1-58)</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:10}} className="gr"><div className="fl"><label>Chaufferie</label><select value={form.chaufferie_type} onChange={e=>upd("chaufferie_type",e.target.value)}><option value="">Choisir</option><option>{"< 30 kW"}</option><option>{"≥ 30 et < 70 kW"}</option><option>{"≥ 70 kW"}</option><option>Autre</option></select></div><SI label="Énergie" field="energie" placeholder="Gaz, PAC, Élec…" form={form} upd={upd}/></div><OBS label="Observations" field="chauffage_obs" form={form} upd={upd}/><div className="sl" style={{marginTop:20}}>Gaz (GZ 1-30)</div><OBS label="Observations" field="gaz_obs" form={form} upd={upd}/><div className="sl" style={{marginTop:20}}>Électricité (EL 1-23)</div><OBS label="Observations" field="elec_obs" form={form} upd={upd}/><div className="sl" style={{marginTop:20}}>Éclairage (EC 1-12)</div><OBS label="Observations" field="eclairage_obs" form={form} upd={upd}/><div className="sl" style={{marginTop:20}}>Ascenseurs (AS 1-11)</div><OBS label="Observations" field="ascenseurs_obs" form={form} upd={upd} placeholder="Ou 'Sans objet'"/><div className="sl" style={{marginTop:20}}>Cuisson (GC 1-20)</div><SI label="Puissance ≥ 20 kW" field="cuisson_puissance" form={form} upd={upd}/><OBS label="Observations" field="cuisson_obs" form={form} upd={upd}/>{navBtns(true)}</div>}

    {step===6&&<div className="si"><div className="sl">Moyens de secours (MS 1-74)</div><h3 style={{fontSize:12,color:"var(--ac)",margin:"0 0 10px"}}>Extinction (MS 4-40)</h3><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:14,marginBottom:10}} className="g3"><SI label="Poteaux (nbre)" field="poteaux_nombre" form={form} upd={upd}/><SI label="Débit (m³/h)" field="poteaux_debit" form={form} upd={upd}/><SI label="Bouches (nbre)" field="bouches_nombre" form={form} upd={upd}/><SI label="Débit (m³/h)" field="bouches_debit" form={form} upd={upd}/><SI label="Réserve (m³)" field="reserve_contenance" form={form} upd={upd}/><SI label="RIA (nbre)" field="ria_nombre" form={form} upd={upd}/></div><OBS label="Extincteurs" field="extincteurs_desc" form={form} upd={upd} placeholder="Nombre, types…"/><OBS label="Ext. adaptés risques" field="extincteurs_adaptes" form={form} upd={upd}/><OBS label="Autres moyens" field="autres_moyens" form={form} upd={upd}/><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>SSI (MS 53-60)</h3><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:10}} className="gr"><div className="fl"><label>Catégorie SSI</label><select value={form.ssi_categorie} onChange={e=>upd("ssi_categorie",e.target.value)}><option value="">Choisir</option><option>A</option><option>B</option><option>C</option><option>D</option><option>E</option></select></div><SI label="Locaux détection (MS 56)" field="ssi_detection_locaux" form={form} upd={upd}/></div><h3 style={{fontSize:12,color:"var(--ac)",margin:"16px 0 10px"}}>Alarme (MS 61-67)</h3><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:10}} className="gr"><div className="fl"><label>Type alarme</label><select value={form.alarme_type} onChange={e=>upd("alarme_type",e.target.value)}><option value="">Choisir</option><option>Type 1</option><option>Type 2a</option><option>Type 2b</option><option>Type 3</option><option>Type 4</option></select></div><SI label="Handicap" field="alarme_handicap" placeholder="Flash, vibreur…" form={form} upd={upd}/></div><OBS label="Alerte (MS 70)" field="alerte_obs" form={form} upd={upd}/><OBS label="Consignes" field="consignes_obs" form={form} upd={upd}/><Rad label="DAE (R.157-1 à R.157-4)" field="dae" form={form} upd={upd}/>{navBtns(true)}</div>}

    {step===7&&<div className="si"><div className="sl">Dérogations (R.143-13, GN 4)</div><Rad label="Demande de dérogation" field="derogation" form={form} upd={upd}/>{form.derogation==="oui"&&<><SI label="Nombre" field="derogation_nombre" form={form} upd={upd}/><OBS label="Détails" field="derogation_details" form={form} upd={upd} placeholder="Règles, justifications, mesures compensatoires…"/></>}<div className="sl" style={{marginTop:24}}>Engagement</div><p style={{fontSize:13,color:"var(--t2)",marginBottom:14,lineHeight:1.6}}>Je soussigné, Maître d'ouvrage, m'engage à respecter les dispositions de la présente notice et les règles générales de construction (CCH).</p><SI label="Signataire" field="signataire" placeholder="Nom et prénom" form={form} upd={upd}/><div style={{display:"flex",gap:10,marginTop:20}}><button className="bg2" onClick={()=>{setError(null);setStep(6);}}>← Retour</button>{!loading&&<button className="ba" onClick={()=>gen(0)}>Générer les observations →</button>}</div>{loading&&<div style={{display:"flex",flexDirection:"column",gap:12,padding:"20px 0"}}>{GS.map((s,i)=><div key={i} className="gs" style={{opacity:i<=genStep?1:.3}}>{i<genStep?<div className="gs-d gs-ok">✓</div>:i===genStep?<div className="gs-sp"/>:<div className="gs-d gs-w">{i+1}</div>}<span style={{color:i<=genStep?"var(--t1)":"var(--t3)"}}>{s}</span></div>)}</div>}</div>}
    </div></div></div></Lay>;

  // DETAIL
  if(view==="detail"&&open){const t=TYPES_ERP[open.typeERP]||{};return<Lay {...layoutProps} title={open.denomination} back={()=>setView("notices")}><div className="fi">
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:24}} className="ms"><div style={{display:"flex",alignItems:"center",gap:14}}><div style={{width:50,height:50,background:"var(--acs)",borderRadius:"var(--r2)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:26}}>{t.icon||"🏢"}</div><div><h1 style={{margin:0,fontSize:21,fontWeight:700,color:"var(--t1)",fontFamily:"var(--fd)"}}>{open.denomination}</h1><div style={{fontSize:12.5,color:"var(--t3)",marginTop:3}}>Type {open.typeERP} · Cat. {open.categorie}</div></div></div><div style={{display:"flex",gap:8}}><button onClick={()=>xPDF(open)} className="bg2" style={{fontSize:13}}>🖨️ PDF officiel</button><button onClick={()=>{if(window.confirm("Supprimer ?"))del(open.id);}} style={{padding:"10px 16px",background:"rgba(239,68,68,.08)",border:"1px solid rgba(239,68,68,.2)",color:"var(--dg)",borderRadius:"var(--r1)",fontSize:13,cursor:"pointer",fontWeight:600}}>✕</button></div></div>
    <div style={{borderBottom:"1px solid var(--b1)",marginBottom:24,display:"flex",overflowX:"auto"}}>{["notice","plan","checklist"].map(t2=><button key={t2} onClick={()=>setTab(t2)} className={`tb ${tab===t2?"ac":""}`}>{t2==="notice"?"📄 Observations":t2==="plan"?"🗺️ Plan":"✅ Checklist"}</button>)}</div>
    {tab==="notice"&&<div className="card" style={{padding:28}}>{open.noticeText?<RN text={open.noticeText}/>:<p style={{color:"var(--t3)",fontStyle:"italic"}}>Les observations apparaîtront ici après génération.</p>}</div>}
    {tab==="plan"&&<div className="card" style={{padding:24}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:18}}><h3 style={{margin:0,fontSize:14,fontWeight:700,color:"var(--t1)",fontFamily:"var(--fd)"}}>Plan d'évacuation</h3><button onClick={savePlan} className="ba" style={{fontSize:12,padding:"8px 16px"}}>💾 Sauvegarder</button></div><Plan plan={plan} setPlan={setPlan}/></div>}
    {tab==="checklist"&&<div className="card" style={{padding:24}}><h3 style={{margin:"0 0 18px",fontSize:14,fontWeight:700,color:"var(--t1)",fontFamily:"var(--fd)"}}>Checklist</h3><CKC checks={gChk(open.id)} setChecks={sChk(open.id)}/></div>}
  </div></Lay>;}
  return null;
}
